 1	import type { FC } from 'react';
 2	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
 3	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 4	import { isPlanEditable } from 'src/plans/details/components/PlanStatus/utils/utils';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { Label } from '@patternfly/react-core';
 8	
 9	import type { EditableDetailsItemProps } from '../../../utils/types';
10	
11	import { getMigrateSharedDisksValue } from './utils/utils';
12	import EditMigrateSharedDisks from './EditMigrateSharedDisks';
13	
14	const SharedDisksDetailsItem: FC<EditableDetailsItemProps> = ({ canPatch, plan, shouldRender }) => {
15	  const { t } = useForkliftTranslation();
16	  const { showModal } = useModal();
17	
18	  if (!shouldRender) return null;
19	
20	  const migrateSharedDisks = getMigrateSharedDisksValue(plan);
21	
22	  return (
23	    <DetailsItem
24	      title={t('Shared disks')}
25	      content={
26	        <Label isCompact color="grey">
27	          {migrateSharedDisks ? t('Migrate shared disks') : t('Do not migrate shared disks')}
28	        </Label>
29	      }
30	      crumbs={['spec', 'migrateSharedDisks']}
31	      onEdit={() => {
32	        showModal(<EditMigrateSharedDisks resource={plan} />);
33	      }}
34	      canEdit={canPatch && isPlanEditable(plan)}
35	    />
36	  );
37	};
38	
39	export default SharedDisksDetailsItem;

